const min = 10;
const max = 20;

// Random integer between 10 and 20
const randomDelay = Math.floor(Math.random() * (max - min + 1)) + min;

return [
  {
    json: {
      wait_seconds: randomDelay
    }
  }
];

// Get the conversation JSON from the node "For each DM1"
const conversation = $('For Each DM').item.json;

// Safety: ensure messages exist
const messages = Array.isArray(conversation.messages) ? conversation.messages : [];

// (Optional) ensure correct order
messages.sort((a, b) => new Date(a.createdAt) - new Date(b.createdAt));

// Map messages into a readable transcript
const transcript = messages
  .map(msg => {
    const sender = msg.sender === "ME" ? "Me" : "Lead";
    return `${sender}: ${msg.body}`;
  })
  .join("\n\n");

return [
  {
    json: {
      conversationId: conversation.id, // or conversation.conversationId if your payload uses that
      linkedInAccountId: conversation.linkedInAccountId,
      leadProfileUrl: conversation.correspondentProfile?.profileUrl,
      messageURL:$input.first().json.messageThreadURL,
      transcript
    }
  }
];

// n8n Code node
const raw = $json.output ?? $json;  // sometimes you'll have {output:"..."} or already an object
let obj;

// 1) Parse JSON safely
try {
  obj = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  // If parsing fails, output a safe default
  return [{
    json: {
      community_invite_present: false,
      lead_reply_segment: [],
      community_accept_intent: "irrelevant",
      add_to_list: false,
      should_reply: false,
      reply: null,
      _parse_error: true,
      _raw: raw
    }
  }];
}

// 2) Normalize lead_reply_segment to array of strings
let seg = obj.lead_reply_segment;

if (Array.isArray(seg)) {
  seg = seg.map(s => String(s)).filter(s => s.trim().length > 0);
} else if (typeof seg === 'string') {
  // Split into lines, keep meaningful lines, cap 6
  seg = seg
    .split(/\n+/)
    .map(s => s.trim())
    .filter(Boolean)
    .slice(0, 6);
} else if (seg == null) {
  seg = [];
} else {
  seg = [String(seg)];
}

// 3) Enforce enum for community_accept_intent
const allowed = new Set(["accept", "ask_clarify", "decline", "irrelevant", "opt_out"]);
let intent = String(obj.community_accept_intent ?? "irrelevant").trim();
if (!allowed.has(intent)) intent = "irrelevant";

// 4) Coerce booleans
const toBool = (v) => v === true || v === "true" || v === 1 || v === "1";

const community_invite_present = toBool(obj.community_invite_present);
const should_reply = toBool(obj.should_reply);

// add_to_list should only be true if invite present AND intent accept
let add_to_list = toBool(obj.add_to_list);
if (!(community_invite_present && intent === "accept")) add_to_list = false;

// 5) reply must be null if should_reply is false
let reply = obj.reply;
if (!should_reply) reply = null;
if (should_reply && (reply == null || String(reply).trim() === "")) {
  // if they said reply is needed but empty, provide a minimal safe default
  reply = "Sounds good — I’ll add you 🙌";
}

// 6) Return normalized object
return [{
  json: {
    community_invite_present,
    lead_reply_segment: seg,
    community_accept_intent: intent,
    add_to_list,
    should_reply,
    reply
  }
}];
